((SELECT d.id FROM desempenos d JOIN capacidades c ON d.capacidad_id = c.id JOIN grados g ON d.grado_id = g.id WHERE c.codigo = 'DPCC-C1-CAP3' AND g.nombre = '3° Secundaria' LIMIT 1), 'Sustenta, con argumentos razonados, una posición ética ante una situación de conflicto moral que involucra los derechos humanos.'),
