((SELECT d.id FROM desempenos d JOIN capacidades c ON d.capacidad_id = c.id JOIN grados g ON d.grado_id = g.id WHERE c.codigo = 'DPCC-C1-CAP3' AND g.nombre = '4° Secundaria' LIMIT 1), 'Expresa opiniones razonadas sobre las consecuencias de sus decisiones, y propone acciones basadas en principios éticos y en la dignidad de las personas.'),
((SELECT d.id FROM desempenos d JOIN capacidades c ON d.capacidad_id = c.id JOIN grados g ON d.grado_id = g.id WHERE c.codigo = 'DPCC-C1-CAP4' AND g.nombre = '4° Secundaria' LIMIT 1), 'Se relaciona con mujeres y varones con equidad y respeto rechazando toda forma de discriminación por identidad de género u orientación sexual. Explica la importancia de establecer vínculos afectivos positivos basados en la reciprocidad, el cuidado del otro y el consentimiento. Rechaza la violencia familiar, sexual y contra la mujer, u otra forma de violencia.'),
